descriptor.controllerScript:
self.onInit = function () {

    var chartDom = document.getElementById('gauge');
    self.chart = echarts.init(chartDom);

    self.renderGauge(0);
};

self.renderGauge = function(value){

    var s = self.ctx.settings || {};

    var min = s.min || 0;
    var max = s.max || 100;
    var greenStart = s.greenStart || 40;
    var greenEnd = s.greenEnd || 60;
    var label = s.label || "";
    var blend = s.colorBlend || "smooth";

    var showTicks = s.showTicks !== false;
    var showLabels = s.showLabels !== false;

    var ratio1 = (greenStart - min) / (max - min);
    var ratio2 = (greenEnd - min) / (max - min);

    var colors;

    if (blend === "hard") {

        colors = [
            [ratio1, '#ff4d4f'],
            [ratio2, '#52c41a'],
            [1, '#ff4d4f']
        ];

    } else {

        colors = [
            [0, '#ff4d4f'],
            [ratio1, '#faad14'],
            [ratio2, '#52c41a'],
            [1, '#ff4d4f']
        ];
    }

    var width = self.ctx.width || 300;

    var fontScale = Math.max(width / 300, 0.6);

    var option = {

        series: [
            {
                type: 'gauge',

                min: min,
                max: max,

                startAngle: 200,
                endAngle: -20,

                radius: '90%',

                axisLine: {
                    lineStyle: {
                        width: 18,
                        color: colors
                    }
                },

                pointer: {
                    width: 4
                },

                axisTick: {
                    show: showTicks,
                    distance: -18
                },

                splitLine: {
                    show: showTicks,
                    length: 12,
                    distance: -18
                },

                axisLabel: {
                    show: showLabels,
                    fontSize: 10 * fontScale
                },

                detail: {
                    fontSize: 28 * fontScale,
                    offsetCenter: [0, '30%'],
                    formatter: function(v){
                        return v.toFixed(1);
                    }
                },

                title: {
                    fontSize: 12 * fontScale,
                    offsetCenter: [0, '60%']
                },

                data: [
                    {
                        value: value,
                        name: label
                    }
                ]
            }
        ]
    };

    self.chart.setOption(option, true);
};

self.onDataUpdated = function () {

    if (!self.ctx.data || !self.ctx.data.length) return;

    var ts = self.ctx.data[0].data;

    if (!ts.length) return;

    var value = parseFloat(ts[ts.length - 1][1]);

    self.renderGauge(value);
};

self.onResize = function () {

    if (!self.chart) return;

    self.chart.resize();

    if (!self.ctx.data || !self.ctx.data.length) return;

    var ts = self.ctx.data[0].data;

    if (!ts.length) return;

    var value = parseFloat(ts[ts.length - 1][1]);

    self.renderGauge(value);
};

self.onDestroy = function () {
    if (self.chart) self.chart.dispose();
};

